{{
  (function() {
    const dbData = get_vm_cached.data || [];

    // 1. Extract unique folder names
    const uniqueFolders = [...new Set(dbData.map(row => row.folder_name))];

    // 2. Map folders to the TreeSelect structure
    return uniqueFolders.map(folderName => {

      // Filter VMs belonging to this folder
      const vmsInFolder = dbData.filter(vm => vm.folder_name === folderName);

      // Create the children array
      const children = vmsInFolder.map(vm => {
        // Evaluate power state to assign the correct indicator
        let statusIcon = '🔴 '; // Default to powered off

        if (vm.power_state === 'poweredOn') {
            statusIcon = '🟢 ';
        } else if (vm.power_state === 'provisioning') {
            statusIcon = '🟡 ';
        }

        return {
          label: statusIcon + vm.vm_name,
          value: vm.vm_moid
        };
      });

      return {
        label: "📁 " + folderName,
        value: "FOLDER::" + folderName, // Use a prefix to distinguish folders from VM UUIDs
        children: children
      };
    });
  })()
}}
